{
  "mode": "method",
  "tests": [
    {
      "name": "get_sso_logins_for_existing_user",
      "input": {
        "userId": "12345"
      },
      "output": [
        {
          "loginType": "google",
          "loginValue": "user@example.com"
        },
        {
          "loginType": "facebook",
          "loginValue": "user_fb@example.com"
        }
      ],
      "args": ["GET", "/users/12345/ssoUserLogins"],
      "notes": "Validates retrieval of SSO logins for an existing user."
    },
    {
      "name": "get_sso_logins_for_nonexistent_user",
      "input": {
        "userId": "99999"
      },
      "output": "User not found",
      "args": ["GET", "/users/99999/ssoUserLogins"],
      "notes": "Tests behavior when trying to get SSO logins for a non-existent user."
    },
    {
      "name": "add_sso_login_for_existing_user",
      "input": {
        "userId": "12345",
        "loginType": "github",
        "loginValue": "user_github@example.com"
      },
      "output": "SSO Login added successfully",
      "args": ["POST", "/users/12345/ssoUserLogin"],
      "notes": "Validates adding a new SSO login for an existing user."
    },
    {
      "name": "add_sso_login_for_nonexistent_user",
      "input": {
        "userId": "99999",
        "loginType": "github",
        "loginValue": "user_github@example.com"
      },
      "output": "User not found",
      "args": ["POST", "/users/99999/ssoUserLogin"],
      "notes": "Tests behavior when trying to add an SSO login for a non-existent user."
    },
    {
      "name": "delete_sso_login_for_existing_user",
      "input": {
        "userId": "12345",
        "loginType": "google"
      },
      "output": "SSO Login deleted successfully",
      "args": ["DELETE", "/users/12345/ssoUserLogin"],
      "notes": "Validates deletion of an existing SSO login."
    },
    {
      "name": "delete_sso_login_for_nonexistent_user",
      "input": {
        "userId": "99999",
        "loginType": "google"
      },
      "output": "User not found",
      "args": ["DELETE", "/users/99999/ssoUserLogin"],
      "notes": "Tests behavior when trying to delete an SSO login for a non-existent user."
    },
    {
      "name": "add_duplicate_sso_login",
      "input": {
        "userId": "12345",
        "loginType": "google",
        "loginValue": "user@example.com"
      },
      "output": "SSO Login already exists",
      "args": ["POST", "/users/12345/ssoUserLogin"],
      "notes": "Tests behavior when trying to add a duplicate SSO login."
    },
    {
      "name": "get_sso_logins_empty_list",
      "input": {
        "userId": "67890"
      },
      "output": [],
      "args": ["GET", "/users/67890/ssoUserLogins"],
      "notes": "Validates retrieval of SSO logins when the user has no logins."
    }
  ],
  "assumptions": "User IDs are unique and valid.",
  "notes": "Ensure proper error handling for non-existent users and duplicate logins."
}
